// ════════════════════════════════════════════════════════
// CONFIG — Only change these values
// ════════════════════════════════════════════════════════

const CONFIG = {
  // Source: LeadConnector Freshdesk help center (server-rendered, crawlable)
  sourceUrl: 'https://help.leadconnectorhq.com/support/solutions',

  // Branding: What to replace in article text
  replacements: [
    { find: /GoHighLevel/gi, replace: 'Nils Platform' },
    { find: /\bGHL\b/g, replace: 'Nils Platform' },
    { find: /HighLevel/gi, replace: 'Nils Platform' },
    { find: /Lead\s*Connector/gi, replace: 'Nils Platform' },
    { find: /LeadConnector/gi, replace: 'Nils Platform' },
  ],

  // URL rewrite: Change source URLs in citations
  // So chatbot citations point to the branded help center
  sourceUrlDomain: 'help.leadconnectorhq.com',
  brandedUrlDomain: 'help.nilsdigital.com',

  // Google File Search Store
  // Replace with the actual store ID from Emilio
  fileSearchStoreId: 'fileSearchStores/nils-platform-support-docs-4womudfm7mg8',
};

// ════════════════════════════════════════════════════════

return [{ json: CONFIG }];

// ════════════════════════════════════════════════════════
// Parse the Freshdesk solutions page
// Extracts all folder URLs and direct article URLs
// ════════════════════════════════════════════════════════

const html = $input.first().json.data || $input.first().json.body || '';
const domain = 'https://help.leadconnectorhq.com';

const results = [];
const seen = new Set();

const linkPattern = /href=["']([^"']+)["']/gi;
let match;

while ((match = linkPattern.exec(html)) !== null) {
  let href = match[1];
  if (href.startsWith('/')) href = domain + href;
  if (!href.startsWith(domain) || seen.has(href)) continue;
  seen.add(href);

  // Article URLs: /support/solutions/articles/XXXXX-slug
  if (href.includes('/support/solutions/articles/')) {
    results.push({ json: { url: href.split('?')[0], type: 'article' } });
  }
  // Folder URLs: /support/solutions/folders/XXXXX
  else if (href.includes('/support/solutions/folders/')) {
    results.push({ json: { url: href.split('?')[0], type: 'folder' } });
  }
  // Category URLs: /support/solutions/XXXXX (numeric or named)
  else if (href.match(/\/support\/solutions\/(?:48|155)\d+/)) {
    results.push({ json: { url: href.split('?')[0], type: 'folder' } });
  }
}

console.log(`Found ${results.filter(r => r.json.type === 'article').length} articles and ${results.filter(r => r.json.type === 'folder').length} folders from main page`);
return results;

// Extract article URLs from a folder/category page
const html = $input.first().json.data || $input.first().json.body || '';
const domain = 'https://help.leadconnectorhq.com';

const results = [];
const seen = new Set();

const linkPattern = /href=["']([^"']+)["']/gi;
let match;

while ((match = linkPattern.exec(html)) !== null) {
  let href = match[1];
  if (href.startsWith('/')) href = domain + href;
  if (!href.startsWith(domain) || seen.has(href)) continue;
  seen.add(href);

  if (href.includes('/support/solutions/articles/')) {
    results.push({ json: { url: href.split('?')[0], type: 'article' } });
  }
}

return results.length > 0 ? results : [{ json: { skip: true } }];

// Merge articles from main page + folders, deduplicate
const items = $input.all();
const seen = new Set();
const unique = [];

for (const item of items) {
  if (item.json.skip) continue;
  const url = item.json.url;
  if (url && !seen.has(url) && url.includes('/articles/')) {
    seen.add(url);
    unique.push({ json: { url } });
  }
}

console.log(`Total unique articles to ingest: ${unique.length}`);

if (unique.length === 0) {
  return [{ json: { error: 'NO_ARTICLES', message: 'No articles found. Check if the help center URL is correct.' } }];
}

return unique;

// ════════════════════════════════════════════════════════
// Extract article text, sanitize branding, rewrite URLs
// ════════════════════════════════════════════════════════

const html = $input.first().json.data || $input.first().json.body || '';
const originalUrl = $('Deduplicate Articles').first().json.url;

// Get config from the Config node
const config = $('Config').first().json;

// ── Extract title ──
const h1Match = html.match(/<h1[^>]*class="heading"[^>]*>([^<]+)<\/h1>/i)
  || html.match(/<h1[^>]*>([^<]+)<\/h1>/i);
const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
let title = (h1Match?.[1] || titleMatch?.[1] || 'Untitled Article').trim();

// ── Extract article body (Freshdesk structure) ──
let articleHtml = html;

// Try to isolate the article content div
const articleMatch = html.match(
  /<div[^>]*class="article-body"[^>]*>([\s\S]*?)<\/div>\s*(?:<\/div>|<div[^>]*class="article-footer)/i
) || html.match(
  /<article[^>]*>([\s\S]*?)<\/article>/i
);
if (articleMatch) {
  articleHtml = articleMatch[1];
}

// ── Strip HTML tags ──
let text = articleHtml
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
  .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '')
  .replace(/<aside[^>]*>[\s\S]*?<\/aside>/gi, '')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/p>/gi, '\n\n')
  .replace(/<\/li>/gi, '\n')
  .replace(/<li[^>]*>/gi, '• ')
  .replace(/<\/h[1-6]>/gi, '\n\n')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/\n{3,}/g, '\n\n')
  .replace(/ {2,}/g, ' ')
  .trim();

// ── Apply branding replacements ──
const replacements = [
  { find: /GoHighLevel/gi, replace: 'Nils Platform' },
  { find: /\bGHL\b/g, replace: 'Nils Platform' },
  { find: /HighLevel/gi, replace: 'Nils Platform' },
  { find: /Lead\s*Connector/gi, replace: 'Nils Platform' },
  { find: /LeadConnector/gi, replace: 'Nils Platform' },
];

for (const r of replacements) {
  text = text.replace(r.find, r.replace);
  title = title.replace(r.find, r.replace);
}

// ── Rewrite source URL for citations ──
const brandedUrl = originalUrl.replace(
  'help.leadconnectorhq.com',
  'help.nilsdigital.com'
);

// ── Skip if content too short (nav-only pages, errors) ──
if (text.length < 150) {
  console.log(`Skipping ${originalUrl} — too short (${text.length} chars)`);
  return [];
}

// ── Build the document for File Search Store ──
const document = [
  `Title: ${title}`,
  `Source: ${brandedUrl}`,
  `Type: Help Article`,
  '',
  text
].join('\n');

console.log(`Processed: ${title} (${document.length} chars)`);

return [{
  json: {
    document,
    title,
    originalUrl,
    brandedUrl,
    charCount: document.length
  }
}];

// ════════════════════════════════════════════════════════
// Ingestion Summary
// ════════════════════════════════════════════════════════

const items = $input.all();
let successful = 0;
let failed = 0;
const errors = [];

for (const item of items) {
  if (item.json.error || item.json.statusCode >= 400) {
    failed++;
    errors.push({
      title: item.json.title || 'Unknown',
      error: item.json.error || `HTTP ${item.json.statusCode}`
    });
  } else {
    successful++;
  }
}

const summary = {
  status: failed === 0 ? '✅ All articles uploaded' : '⚠️ Some uploads failed',
  totalProcessed: items.length,
  successful,
  failed,
  timestamp: new Date().toISOString(),
};

if (errors.length > 0) {
  summary.errors = errors.slice(0, 10); // Show first 10 errors
}

console.log(JSON.stringify(summary, null, 2));
return [{ json: summary }];
